-- ElinMS @shop (GM Shop) seed data.
-- 96 shops (shopid 8000-8095, npcid 9010000 = Maple Administrator) organized by class,
-- every item priced at 1 meso. Cash-shop items excluded. Ordered by reqLevel so the client
-- displays lowest-level items first as you scroll (position is emitted DESCENDING because the
-- client renders the shop list in descending position order). Opened via the @shop command
-- (client/command/commands/gm0/ShopCommand.java -> scripts/npc/gm_shop.js).
-- Regenerated from WZ by scratchpad/gen_shop3.ps1 (buckets equips by reqJob/slot, consumes by prefix).
-- shopitemid is auto-assigned (omitted) so this is safe to load after the base shopitems seed.

DELETE FROM shopitems WHERE shopid BETWEEN 8000 AND 8399;
DELETE FROM shops WHERE shopid BETWEEN 8000 AND 8399;
